board.suspendUpdate();
var yOffset = -60;
board.create('circle', [[0, yOffset], 6], {fillColor: '#cc0000', strokeColor: '#cc0000'});
board.create('polygon', [[-2.5, 50], [2.5, 50], [2.5, yOffset+4], [-2.5, yOffset+4]], {fillColor: '#f8f9fa', strokeColor: '#475569', borders: {strokeWidth: 1}});
board.create('polygon', [[-1.5, 10], [1.5, 10], [1.5, yOffset+4], [-1.5, yOffset+4]], {fillColor: '#cc0000', strokeColor: '#cc0000', borders: {strokeWidth: 0}});
board.create('text', [0, 58, '°C'], {anchorX: 'middle', fontSize: 14});
for (var i = -60; i <= 50; i += 10) {
  board.create('segment', [[2.5, i], [6, i]], {strokeColor: '#475569'});
  board.create('text', [8, i, i.toString()], {anchorY: 'middle', fontSize: 12});
}
for (var i = -60; i <= 50; i += 2) {
  if (i % 10 !== 0) board.create('segment', [[2.5, i], [4.5, i]], {strokeColor: '#475569', strokeWidth: 1});
}
board.unsuspendUpdate();

